import { readFileSync, readdirSync, writeFileSync } from 'node:fs';
import { createRequire } from 'node:module';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const require = createRequire(import.meta.url);
const { CookiebiteTheme } = require('../assets/theme-compiler.js');

const root = path.dirname(path.dirname(fileURLToPath(import.meta.url)));
const presetsDir = path.join(root, 'assets', 'presets');
const outFile = path.join(root, 'assets', 'presets.generated.js');

function buildCatalog() {
  const catalog = {};
  for (const file of readdirSync(presetsDir).filter((name) => name.endsWith('.json')).sort()) {
    const preset = JSON.parse(readFileSync(path.join(presetsDir, file), 'utf8'));
    if (!preset.seed) continue;
    const document = { schemaVersion: 1, seed: preset.seed };
    if (preset.font && preset.font.url) document.resources = { fontStylesheets: [preset.font.url] };
    if (preset.locale) document.locale = preset.locale;
    CookiebiteTheme.compile(document); // fail fast: a preset that cannot compile never ships
    catalog[preset.name] = { label: preset.label, document };
  }
  return catalog;
}

function render(catalog) {
  return `// GENERATED by scripts/build-preset-bundle.mjs — do not edit by hand.
(function exposePresets(root, catalog) {
  root.CookiebitePresets = catalog;
  if (typeof module !== 'undefined' && module.exports) module.exports = catalog;
}(typeof globalThis !== 'undefined' ? globalThis : this, ${JSON.stringify(catalog, null, 2)}));
`;
}

const output = render(buildCatalog());

if (process.argv.includes('--check')) {
  const current = readFileSync(outFile, 'utf8');
  if (current !== output) {
    console.error('assets/presets.generated.js is stale. Run: node scripts/build-preset-bundle.mjs');
    process.exit(1);
  }
  console.log('assets/presets.generated.js is up to date');
} else {
  writeFileSync(outFile, output);
  console.log(`wrote ${Object.keys(buildCatalog()).length} presets to assets/presets.generated.js`);
}
